+        .collect();
+
+    let mut results = Vec::new();
+    let mut mapping: Vec<Option<usize>> = vec![None; n];
+    let mut used = vec![false; n];
+
+    #[allow(clippy::too_many_arguments)]
+    fn backtrack(
