+            return;
+        }
+
+        let u = depth;
+        for v in 0..n {
+            if used[v] || deg1[u] != deg2[v] {
+                continue;
+            }
+
+            let mut consistent = true;
+            for prev_u in 0..depth {
+                if let Some(prev_v) = mapping[prev_u]
+                    && (adj1[u][prev_u] != adj2[v][prev_v] || adj1[prev_u][u] != adj2[prev_v][v])
